"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[8865],{62843(e,o,r){r.r(o),r.d(o,{assets:()=>s,contentTitle:()=>t,default:()=>d,frontMatter:()=>i,metadata:()=>n,toc:()=>l});const n=JSON.parse('{"id":"UserGuide/C22_Color/S03_Color_spaces_and_converting_between_them","title":"Color spaces and converting between them","description":"A color space is a mathematical model that typically has three bands with which to describe color data, such as RGB (red, green, blue). Note that we use the term color bands, but they are also known as color components. Regardless of whether you are using the Aurora Imaging Library Color Analysis module to perform color transformation using relative color calibration (McolTransform), matching (McolMatch), projection (McolProject), or distance (McolDistance), color data is always interpreted according to a specific color space.","source":"@site/docs/UserGuide/C22_Color/S03_Color_spaces_and_converting_between_them.md","sourceDirName":"UserGuide/C22_Color","slug":"/UserGuide/C22_Color/S03_Color_spaces_and_converting_between_them","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C22_Color/S03_Color_spaces_and_converting_between_them","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"doctype":"UserGuide","part":"2D processing and analysis","chapter":"Color","section":"Color_spaces_and_converting_between_them","module_tag":"col","product":"Aurora-Imaging-Library-user-guide","version":1100,"path":"UserGuide / 2D processing and analysis / color / Color spaces and converting between them"},"sidebar":"userGuideSidebar","previous":{"title":"Basic concepts for the Aurora Imaging Library Color Analysis module","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C22_Color/S02_Basic_concepts"},"next":{"title":"Relative color calibration","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C22_Color/S04_Relative_color_calibration"}}');var c=r(74848),a=r(28453);const i={doctype:"UserGuide",part:"2D processing and analysis",chapter:"Color",section:"Color_spaces_and_converting_between_them",module_tag:"col",product:"Aurora-Imaging-Library-user-guide",version:1100,path:"UserGuide / 2D processing and analysis / color / Color spaces and converting between them"},t="Color spaces and converting between them",s={},l=[{value:"Color spaces",id:"color-spaces",level:2},{value:"RGB",id:"rgb",level:3},{value:"HSL",id:"hsl",level:3},{value:"HSV",id:"hsv",level:3},{value:"CIELAB",id:"cielab",level:3},{value:"Source color space",id:"source-color-space",level:2},{value:"Converting between color spaces",id:"converting-between-color-spaces",level:2},{value:"Normalizing the RGB color space",id:"normalizing-the-rgb-color-space",level:3},{value:"Reference color space",id:"reference-color-space",level:3},{value:"Gamma correction",id:"gamma-correction",level:3}];function h(e){const o={a:"a",blockquote:"blockquote",code:"code",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,c.jsxs)(c.Fragment,{children:[(0,c.jsx)(o.header,{children:(0,c.jsx)(o.h1,{id:"color-spaces-and-converting-between-them",children:"Color spaces and converting between them"})}),"\n",(0,c.jsxs)(o.p,{children:["A color space is a mathematical model that typically has three bands with which to describe color data, such as RGB (red, green, blue). Note that we use the term color bands, but they are also known as color components. Regardless of whether you are using the Aurora Imaging Library Color Analysis module to perform color transformation using relative color calibration (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolTransform",children:(0,c.jsx)(o.code,{children:"McolTransform"})}),"), matching (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolMatch",children:(0,c.jsx)(o.code,{children:"McolMatch"})}),"), projection (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolProject",children:(0,c.jsx)(o.code,{children:"McolProject"})}),"), or distance (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolDistance",children:(0,c.jsx)(o.code,{children:"McolDistance"})}),"), color data is always interpreted according to a specific color space."]}),"\n",(0,c.jsx)(o.h2,{id:"color-spaces",children:"Color spaces"}),"\n",(0,c.jsx)(o.p,{children:"The major color spaces used today are RGB, HSL, HSV, and CIELAB, each of which has unique qualities with which to represent color."}),"\n",(0,c.jsx)(o.p,{children:(0,c.jsx)(o.em,{children:"[Image: Color_Spaces.png]"})}),"\n",(0,c.jsxs)(o.p,{children:["The color space that you use throughout an application must be consistent otherwise results can be skewed. For example, when calculating the distance between two color images or when performing a color match, all your color data should be in the same color space. For ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolTransform",children:(0,c.jsx)(o.code,{children:"McolTransform"})})," and ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolMatch",children:(0,c.jsx)(o.code,{children:"McolMatch"})}),", you must also consider the context's source color space. For more information, see ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C22_Color/S03_Color_spaces_and_converting_between_them",children:"Source color space"}),"."]}),"\n",(0,c.jsx)(o.h3,{id:"rgb",children:"RGB"}),"\n",(0,c.jsx)(o.p,{children:"RGB is based on red, green, and blue color band values. Typically, these bands are directly used for acquiring and displaying color. For example, when displaying a color image buffer, the first band is routed to the monitor's first output channel (usually red), the second band to the second channel (usually green), and the third band to the third channel (usually blue)."}),"\n",(0,c.jsx)(o.p,{children:"The RGB color space can be seen as a cube with a red, green, and blue axis. Colors located at the origin, [0, 0, 0], are considered to be black, while colors located at [255, 255, 255] (for an 8-bit buffer) are considered to be white. All other colors can be represented as a combination of red, green, and blue values within this range."}),"\n",(0,c.jsx)(o.p,{children:"Acquisition and display devices can render RGB data differently. Since RGB maps to such devices, it is a device-dependent color space."}),"\n",(0,c.jsx)(o.p,{children:(0,c.jsx)(o.em,{children:"[Image: Color_MonitorRGBDifference.png]"})}),"\n",(0,c.jsx)(o.p,{children:"Theoretically, there are as many RGB color spaces as there are color devices. Although there will always be some variance, color devices typically adhere to certain internationally accepted standards. To interpret color space data, Aurora Imaging Library uses standard RGB specifications (sRGB), as defined by the International Electrotechnical Commission (IEC) Project Team 61966-2-1."}),"\n",(0,c.jsx)(o.h3,{id:"hsl",children:"HSL"}),"\n",(0,c.jsx)(o.p,{children:"HSL is established from an RGB color model, but is based on hue, saturation, and luminance color band values. Since such bands are generally more intuitive, HSL can be seen as a color space designed to mimic the human way of describing colors. Like RGB, HSL is device-dependent."}),"\n",(0,c.jsx)(o.p,{children:"In RGB, every color is a mixture of red, green, and blue, which can make it difficult to ascertain the exact band values of a particular color. However, in HSL, the color's hue is stored as a separate band (H), which is represented as an angular position on a circular color disk. The other bands control only the color's purity (S) and lightness (or luminance, L), which can be used to alter the color's quality, but not the color's basic hue. In the diagram below, the lightness (or luminance) band extends from one point of a bicone to the other, from black (0% lightness) to white (100% lightness). The colors at the center disk are situated at 50% lightness."}),"\n",(0,c.jsx)(o.p,{children:(0,c.jsx)(o.em,{children:"[Image: Color_hsl.png]"})}),"\n",(0,c.jsxs)(o.p,{children:["With the HSL model, band independence makes color manipulation much simpler. Most applications that allow for an interactive manipulation of colors represent the color with HSL. You can, for example, perform color matching with the hue (color) band only, using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"McolControl"})})," with ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_BAND_MODE"})})," set to ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_COLOR_BAND_0"})}),". This can solve certain problems, such as matching dark orange and bright orange, which can be difficult in RGB. Also, matching the hue independently of the luminance can be useful if your image has non-uniform lighting, shadows, or highlights."]}),"\n",(0,c.jsx)(o.h3,{id:"hsv",children:"HSV"}),"\n",(0,c.jsx)(o.p,{children:"HSV resembles HSL, except the third band is called value, and represents brightness as if the white point of the HSL model has been compressed to the central disk. In the diagram below, the model is shown as a simple cone, with hue (H) positioned around a circular disk, and saturation (S) increasing from the center out. The value (V) band ranges from black (the far point of the cone below the disk) to white (the center of the disk)."}),"\n",(0,c.jsx)(o.p,{children:(0,c.jsx)(o.em,{children:"[Image: Color_hsv.png]"})}),"\n",(0,c.jsx)(o.p,{children:"In this model, 100% brightness (or value) corresponds to maximum color richness, offering an intuitive advantage over HSL, which represents the richest colors at only 50% lightness."}),"\n",(0,c.jsx)(o.p,{children:"The HSV color space reflects how paint colors change when creating tints (adding white) or shades (adding black), which is intuitively easy to understand. As with HSL, the separate bands allow for interactive manipulation."}),"\n",(0,c.jsx)(o.h3,{id:"cielab",children:"CIELAB"}),"\n",(0,c.jsx)(o.p,{children:"CIELAB (or LAB) is based on the color's luminance (L), its position between red and green (A), and its position between yellow and blue (B). Unlike RGB and HSL, LAB is intended to be device-independent, and was developed as a distinct color model intended to represent a completely human interpretation of color using statistical data taken from visual experiments. Color differences in LAB vary proportionally with human perception. For example, if two colors are at a distance of 5, they will appear roughly 5 times as different as two colors at a distance of 1. LAB was designed to be perceptually uniform, making it a good space to measure color difference."}),"\n",(0,c.jsx)(o.p,{children:"Since LAB is based on color perception, its mathematical model better represents how humans distinguish color, and color differences are more meaningful. This can be seen in the following example, where you have to choose which color, A or B, is closer to color X."}),"\n",(0,c.jsx)(o.p,{children:(0,c.jsx)(o.em,{children:"[Image: Color_RGBCIELABCompare.png]"})}),"\n",(0,c.jsx)(o.p,{children:"Mathematically, color A is the closest color, in an RGB color space. However, color B is intuitively closer, which is also what the distance in the LAB color space mathematically represents."}),"\n",(0,c.jsx)(o.p,{children:(0,c.jsx)(o.em,{children:"[Image: Color_RGBCIELABCompare2.png]"})}),"\n",(0,c.jsx)(o.p,{children:"It can be preferable to use CIELAB over RGB since, like HSL, you can use CIELAB to discard the luminance (band L), and perform color matching with only band A and band B. Also, CIELAB can be more robust with colors that are visually alike, especially for minor color differences. For example, when matching a red target among color-samples with similar shades of red, CIELAB can outperform RGB and HSL."}),"\n",(0,c.jsx)(o.p,{children:"With CIELAB, distances have been standardized by the International Commission on Illumination (CIE). A color distance of 1 with CIELAB corresponds to the smallest possible color difference a human can perceive."}),"\n",(0,c.jsx)(o.h2,{id:"source-color-space",children:"Source color space"}),"\n",(0,c.jsxs)(o.p,{children:["When allocating a color matching or a relative color calibration context using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"McolAlloc"})}),", you must set the context's source color space to one of the following color spaces: ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"M_RGB"})}),", ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"M_HSL"})}),", or ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"M_CIELAB"})}),". Relative color calibration contexts must be ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"M_RGB"})}),"."]}),"\n",(0,c.jsxs)(o.blockquote,{children:["\n",(0,c.jsxs)(o.p,{children:[(0,c.jsx)(o.strong,{children:"Note:"}),' Note that you should not confuse "color space", which is the mathematical model used to describe color, and "source color space," which is the specific color space in which the color matching context is defined. Advanced users should also be aware of the "reference color space," which refers to how Aurora Imaging Library interprets the color data of the source color space when performing an internal conversion before the color operation. For more information, see ',(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C22_Color/S03_Color_spaces_and_converting_between_them",children:"Converting between color spaces"}),"."]}),"\n"]}),"\n",(0,c.jsxs)(o.p,{children:["Aurora Imaging Library considers all color data required for color matching or relative color calibration to be in the source color space specified for the context. For example, if you set an ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"M_HSL"})})," source color space, Aurora Imaging Library assumes that the target image (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolMatch",children:(0,c.jsx)(o.code,{children:"McolMatch"})}),"), as well as the color-sample elements (whether they be defined by an image or by triplet values using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolDefine",children:(0,c.jsx)(o.code,{children:"McolDefine"})}),"), are also HSL. If they are not, Aurora Imaging Library still interprets and matches the color data as if it was HSL and does not produce an error. Therefore, unless all the color data is consistent with the source color space, you can receive misleading results."]}),"\n",(0,c.jsxs)(o.p,{children:["Since color data is interpreted according to the context's source color space, be careful when restoring color images into an automatically allocated data buffer using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/buf/MbufRestore",children:(0,c.jsx)(o.code,{children:"MbufRestore"})}),", when the color's type is not explicitly known. For example, if you are working in an ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"M_RGB"})})," color space, and you use an image restored from a file that contained YUV data, the Y, U, and V bands will be incorrectly read as R, G, and B bands, respectively. Instead, you should use ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/buf/MbufAllocColor",children:(0,c.jsx)(o.code,{children:"MbufAllocColor"})})," to allocate a color data buffer with an explicit data type (for example, ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/buf/MbufAllocColor",children:(0,c.jsx)(o.code,{children:"M_RGB24"})}),"), and then use ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/buf/MbufLoad",children:(0,c.jsx)(o.code,{children:"MbufLoad"})})," to load the data from the color image into the specified color data buffer. In this case, ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/buf/MbufLoad",children:(0,c.jsx)(o.code,{children:"MbufLoad"})})," will convert the image's color data to the proper type, as defined by the buffer (for example, ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/buf/MbufAllocColor",children:(0,c.jsx)(o.code,{children:"M_RGB24"})}),")."]}),"\n",(0,c.jsxs)(o.p,{children:["When matching, you must set the encoding of the source color space according to the actual dynamic range of your color data, using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"McolControl"})})," with ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_ENCODING"})}),". By default, an 8-bit source color space encoding is assumed, regardless of the depth of your buffers. Since Aurora Imaging Library processes color data as is (even if it is inconsistent), you must remember to modify the encoding control according to your data, otherwise you can get incorrect results. For example, you will not get an error if you match a 16-bit target area with an 8-bit color-sample. Therefore if your color data was acquired with a 16-bit camera, you should set ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_ENCODING"})})," to ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_16BIT"})}),". For more information, see ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C22_Color/S08_Advanced_color_matching_settings",children:"Color space encoding"}),"."]}),"\n",(0,c.jsx)(o.h2,{id:"converting-between-color-spaces",children:"Converting between color spaces"}),"\n",(0,c.jsxs)(o.p,{children:["You can convert color data between HSL and RGB color spaces using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"MimConvert"})})," with ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_HSL_TO_RGB"})})," or ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_RGB_TO_HSL"})}),". For efficiency when converting from a 3-band (RGB) buffer, you can calculate just the hue band of the HSL color space and save it in a 1-band buffer (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_RGB_TO_H"})}),"). For more information on the algorithm used to convert between HSL and RGB color spaces, see ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C22_Color/S05_Converting_to_grayscale",children:"Extracting the luminance"}),"."]}),"\n",(0,c.jsxs)(o.p,{children:["When using an RGB source color space (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"McolAlloc"})}),"), you can use ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolSetMethod",children:(0,c.jsx)(o.code,{children:"McolSetMethod"})})," with the ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolSetMethod",children:(0,c.jsx)(o.code,{children:"ConversionModeOrComputeOption"})})," parameter to convert your RGB data to CIELAB or HSL before performing ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolMatch",children:(0,c.jsx)(o.code,{children:"McolMatch"})}),". This type of conversion can be useful if, for example, you have allocated a color matching context in an RGB color space, but you want to calculate with CIELAB or HSL colors. Note that when performing multiple match operations on RGB data in CIELAB or HSL, you might want to consider providing images that have already been converted to CIELAB or HSL, which might be faster."]}),"\n",(0,c.jsxs)(o.p,{children:["When converting with ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolSetMethod",children:(0,c.jsx)(o.code,{children:"McolSetMethod"})}),", the converted color is essentially the same as the source color, except that it is represented in a different color space, and therefore has different (converted) color band values. For example, pure red has an RGB value of (255, 0, 0), while in HSL the same red has a value of (0, 255, 128). As shown in the following illustration, if you are using an RGB source color space, all color data (such as the color-sample elements) is assumed to be in RGB. However, if you use ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolSetMethod",children:(0,c.jsx)(o.code,{children:"McolSetMethod"})})," to convert from RGB to HSL, the match operation is performed with the HSL version of the color. Note that in the following example, the target image is already in HSL."]}),"\n",(0,c.jsx)(o.p,{children:(0,c.jsx)(o.em,{children:"[Image: color_conversion_mode_rgb.png]"})}),"\n",(0,c.jsxs)(o.p,{children:["You can also use ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"MimConvert"})})," to convert sRGB to LAB (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_SRGB_TO_LAB"})}),"), and to convert LAB to sRGB (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_LAB_TO_SRGB"})}),"). In these cases, your RGB data must adhere to the IEC standards for sRGB (previously discussed); otherwise, unexpected results can occur. To obtain sRGB color, you can grab images using an sRGB camera and illuminant in a favorable environment. You can also perform a relative color calibration on an RGB image to transform it to sRGB, using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolTransform",children:(0,c.jsx)(o.code,{children:"McolTransform"})})," and an sRGB ColorChecker. For more information, see ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C22_Color/S04_Relative_color_calibration",children:"Relative color calibration"}),"."]}),"\n",(0,c.jsxs)(o.p,{children:["Instead of LAB, you can use ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"MimConvert"})})," to convert sRGB to and from LCH (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_SRGB_TO_LCH"})})," or ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_LCH_TO_SRGB"})}),"). The LCH color space is a reinterpretation of LAB that emphasizes polar coordinates (absolute black and absolute white), which can make LAB colors easier to deal with (similar to HSL being easier to deal with than RGB). LCH is based on luminance (L), chroma (C), and hue (H)."]}),"\n",(0,c.jsxs)(o.p,{children:["If you are converting to and from linear sRGB data (not gamma corrected), you must use the linear version of the sRGB conversion values (",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_SRGB_LINEAR_TO_LAB"})}),", ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_SRGB_LINEAR_TO_LCH"})}),", ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_LAB_TO_SRGB_LINEAR"})}),", or ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_LCH_TO_SRGB_LINEAR"})}),"). For more information, see ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C22_Color/S03_Color_spaces_and_converting_between_them",children:"Gamma correction"}),"."]}),"\n",(0,c.jsxs)(o.blockquote,{children:["\n",(0,c.jsxs)(o.p,{children:[(0,c.jsx)(o.strong,{children:"Note:"})," ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"MimConvert"})})," is available with Aurora Imaging Library Lite, while ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolSetMethod",children:(0,c.jsx)(o.code,{children:"McolSetMethod"})})," requires the full version of Aurora Imaging Library."]}),"\n"]}),"\n",(0,c.jsx)(o.h3,{id:"normalizing-the-rgb-color-space",children:"Normalizing the RGB color space"}),"\n",(0,c.jsx)(o.p,{children:"Normalizing a color space can help remove unwanted variations in shades from an image. For example, using blob analysis on images with shadows or sharp variations of the same color might find false borders, and return inaccurate results. You can fix the unwanted variations in color shades by normalizing the colorspace."}),"\n",(0,c.jsxs)(o.p,{children:["Using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"MimConvert"})})," with ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"M_RGB_NORMALIZE"})})," on an RGB image will normalize the color of each pixel to smooth variations in shade. The bands of each individual pixel are divided by the sum of that pixel's band values. This division results in a number between 0 and 1 (inclusive) for every band, and has the effect of reducing variations over similar colors. If the destination buffer is an integer buffer, the normalized bands are then multiplied by the depth of the buffer; this scales the values, but retains the relative difference between the other colors."]}),"\n",(0,c.jsxs)(o.p,{children:["After converting the RGB color data to normalized RGB data, you can convert it to any other color space with ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/im/MimConvert",children:(0,c.jsx)(o.code,{children:"MimConvert"})}),", and keep the normalized separations between colors in your image."]}),"\n",(0,c.jsx)(o.h3,{id:"reference-color-space",children:"Reference color space"}),"\n",(0,c.jsxs)(o.p,{children:["To interpret the RGB source color space data when using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolSetMethod",children:(0,c.jsx)(o.code,{children:"McolSetMethod"})})," with the CIELAB conversion mode, the color matching context uses standard RGB specifications (sRGB) as its reference color space, which you can specify using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"McolAlloc"})})," with the ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"ColorSpaceProfileId"})})," parameter. sRGB specifications are defined in the International Electrotechnical Commission (IEC) 61966-2-1. Note that when converting RGB using the HSL conversion mode, the reference color space is not required since HSL is based on the RGB color model."]}),"\n",(0,c.jsx)(o.h3,{id:"gamma-correction",children:"Gamma correction"}),"\n",(0,c.jsx)(o.p,{children:"Depending on the display device, the colors of grabbed images can appear over-saturated or too dark. This is typically caused by a non-linear relationship between a pixel's value and its displayed intensity. To compensate for this discrepancy, the acquisition process (for example, the camera doing the grab) can apply a gamma correction, thereby leaving your color data in a corrected (non-linear) state."}),"\n",(0,c.jsxs)(o.p,{children:["When converting RGB source colors before the match using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolSetMethod",children:(0,c.jsx)(o.code,{children:"McolSetMethod"})})," with the CIELAB conversion mode, Aurora Imaging Library requires uncorrected (linear) color data. Therefore, if gamma correction has been applied on the RGB source color data, you must remove it using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"McolControl"})})," with ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_CONVERSION_GAMMA"})})," set to ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_ENABLE"})}),"."]}),"\n",(0,c.jsxs)(o.p,{children:["By default, Aurora Imaging Library assumes the RGB source color data is in a corrected (non-linear) state, and removes the correction. Aurora Imaging Library also assumes that the data has been corrected according to the standards of the context's reference color space, as specified using ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"McolAlloc"})})," with the ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolAlloc",children:(0,c.jsx)(o.code,{children:"ColorSpaceProfileId"})})," parameter. Aurora Imaging Library uses these standards (for example, sRGB) to remove the gamma correction. If your RGB source color data is in an uncorrected (linear) state, you must set ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_CONVERSION_GAMMA"})})," to ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_DISABLE"})}),"."]}),"\n",(0,c.jsxs)(o.p,{children:["Regardless of whether your RGB source color data is in a corrected or uncorrected state, Aurora Imaging Library removes or keeps the correction according to ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_CONVERSION_GAMMA"})})," and, in the case of removing the correction, applies the standards of the reference color space (sRGB). Therefore, you will not receive an error if, for example, your color data is not corrected (linear) and you set ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_CONVERSION_GAMMA"})})," to ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_ENABLE"})})," (to remove the correction). Such a scenario would, in all likelihood, render inaccurate results."]}),"\n",(0,c.jsxs)(o.p,{children:["Unless you are using the CIELAB conversion mode in an RGB source color space, ",(0,c.jsx)(o.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/col/McolControl",children:(0,c.jsx)(o.code,{children:"M_CONVERSION_GAMMA"})})," is ignored."]})]})}function d(e={}){const{wrapper:o}={...(0,a.R)(),...e.components};return o?(0,c.jsx)(o,{...e,children:(0,c.jsx)(h,{...e})}):h(e)}},28453(e,o,r){r.d(o,{R:()=>i,x:()=>t});var n=r(96540);const c={},a=n.createContext(c);function i(e){const o=n.useContext(a);return n.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function t(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(c):e.components||c:i(e.components),n.createElement(a.Provider,{value:o},e.children)}}}]);